Follow these practices for clean, maintainable React components.

**Keep Components Small:**
```jsx
// BAD - Large component doing too much
function UserProfile() {
  // 200 lines of code
  return <div>...</div>;
}

// GOOD - Small, focused components
function UserProfile() {
  return (
    <div>
      <UserHeader />
      <UserDetails />
      <UserActions />
    </div>
  );
}
```

**Single Responsibility:**
```jsx
// Each component should have one job
function UserAvatar({ src, alt }) {
  return <img src={src} alt={alt} />;
}

function UserName({ name }) {
  return <h2>{name}</h2>;
}

function UserEmail({ email }) {
  return <p>{email}</p>;
}
```

**Use Functional Components:**
```jsx
// Preferred - Functional component with hooks
function MyComponent() {
  const [state, setState] = useState();
  return <div>{state}</div>;
}

// Avoid - Class components (unless necessary)
class MyComponent extends React.Component {
  render() {
    return <div>{this.state}</div>;
  }
}
```

**Descriptive Naming:**
```jsx
// Good - Descriptive names
function UserLoginForm() {}
function ProductCard() {}
function NavigationBar() {}

// Bad - Vague names
function Form() {}
function Card() {}
function Bar() {}
```

Choose the right state management approach for your application.

**Local State (useState):**
```jsx
// Use for component-specific state
function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(count + 1)}>{count}</button>;
}
```

**Lifting State Up:**
```jsx
// Share state between components by lifting it up
function Parent() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <ChildA count={count} setCount={setCount} />
      <ChildB count={count} setCount={setCount} />
    </div>
  );
}
```

**Context API (Global State):**
```jsx
// Use for app-wide state
const ThemeContext = createContext('light');

function App() {
  const [theme, setTheme] = useState('light');

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      <Child />
    </ThemeContext.Provider>
  );
}
```

**When to Use External State Management:**
- Redux/Zustand: Complex state, many components
- React Query/SWR: Server state, caching
- Recoil/Jotai: Atomic state, fine-grained updates

Optimize React applications for better performance.

**useMemo for Expensive Calculations:**
```jsx
function ExpensiveComponent({ data }) {
  const sortedData = useMemo(() => {
    return data.sort((a, b) => a.value - b.value);
  }, [data]);

  return <div>{sortedData.map(item => <div key={item.id}>{item.name}</div>)}</div>;
}
```

**useCallback for Function References:**
```jsx
function Parent() {
  const [count, setCount] = useState(0);

  const handleClick = useCallback(() => {
    console.log('Clicked');
  }, []);

  return <Child onClick={handleClick} />;
}
```

**React.memo for Component Memoization:**
```jsx
const ExpensiveChild = React.memo(function ExpensiveChild({ data }) {
  console.log('Rendering child');
  return <div>{data}</div>;
});
```

**Code Splitting:**
```jsx
import { lazy, Suspense } from 'react';

const HeavyComponent = lazy(() => import('./HeavyComponent'));

function App() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <HeavyComponent />
    </Suspense>
  );
}
```

**Virtualization for Long Lists:**
```jsx
import { FixedSizeList } from 'react-window';

function LongList({ items }) {
  return (
    <FixedSizeList
      height={400}
      itemCount={items.length}
      itemSize={35}
      width={300}
    >
      {({ index, style }) => (
        <div style={style}>{items[index]}</div>
      )}
    </FixedSizeList>
  );
}
```

Use established patterns for common React scenarios.

**Compound Components:**
```jsx
function Tabs({ children }) {
  const [activeTab, setActiveTab] = useState(0);

  return (
    <TabsContext.Provider value={{ activeTab, setActiveTab }}>
      {children}
    </TabsContext.Provider>
  );
}

function Tab({ children, index }) {
  const { activeTab, setActiveTab } = useContext(TabsContext);

  return (
    <button onClick={() => setActiveTab(index)}>
      {children}
    </button>
  );
}

function TabPanel({ children, index }) {
  const { activeTab } = useContext(TabsContext);

  if (activeTab !== index) return null;
  return <div>{children}</div>;
}
```

**Render Props:**
```jsx
function MouseTracker({ render }) {
  const [position, setPosition] = useState({ x: 0, y: 0 });

  return (
    <div onMouseMove={e => setPosition({ x: e.clientX, y: e.clientY })}>
      {render(position)}
    </div>
  );
}

function App() {
  return (
    <MouseTracker render={({ x, y }) => (
      <p>Mouse position: {x}, {y}</p>
    )} />
  );
}
```

**Higher-Order Components:**
```jsx
function withLoading(WrappedComponent) {
  return function WithLoadingComponent({ isLoading, ...props }) {
    if (isLoading) return <div>Loading...</div>;
    return <WrappedComponent {...props} />;
  };
}

const UserListWithLoading = withLoading(UserList);
```

**Custom Hooks Pattern:**
```jsx
function useLocalStorage(key, initialValue) {
  const [value, setValue] = useState(() => {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : initialValue;
  });

  useEffect(() => {
    localStorage.setItem(key, JSON.stringify(value));
  }, [key, value]);

  return [value, setValue];
}
```

React Router is the standard routing library for React applications, enabling navigation between different components.

**Installation:**
```bash
npm install react-router-dom
```

**Basic Setup:**
```jsx
import { BrowserRouter, Routes, Route } from 'react-router-dom';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/contact" element={<Contact />} />
      </Routes>
    </BrowserRouter>
  );
}
```

**Navigation Links:**
```jsx
import { Link } from 'react-router-dom';

function Navigation() {
  return (
    <nav>
      <Link to="/">Home</Link>
      <Link to="/about">About</Link>
      <Link to="/contact">Contact</Link>
    </nav>
  );
}
```

**Programmatic Navigation:**
```jsx
import { useNavigate } from 'react-router-dom';

function LoginForm() {
  const navigate = useNavigate();

  const handleSubmit = () => {
    // After successful login
    navigate('/dashboard');
  };

  return <button onClick={handleSubmit}>Login</button>;
}
```

**Dynamic Routes:**
```jsx
function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/users/:id" element={<UserProfile />} />
      </Routes>
    </BrowserRouter>
  );
}

function UserProfile() {
  const { id } = useParams();
  return <div>User ID: {id}</div>;
}
```

**Nested Routes:**
```jsx
function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/dashboard" element={<DashboardLayout />}>
          <Route path="settings" element={<Settings />} />
          <Route path="profile" element={<Profile />} />
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

function DashboardLayout() {
  return (
    <div>
      <Sidebar />
      <Outlet />
    </div>
  );
}
```

**Protected Routes:**
```jsx
function ProtectedRoute({ isAuthenticated, children }) {
  if (!isAuthenticated) {
    return <Navigate to="/login" />;
  }
  return children;
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/dashboard" element={
          <ProtectedRoute isAuthenticated={user}>
            <Dashboard />
          </ProtectedRoute>
        } />
      </Routes>
    </BrowserRouter>
  );
}
```

**Best Practices:**
- Use BrowserRouter for web applications
- Keep routes organized in a central location
- Use descriptive route paths
- Implement protected routes for authenticated pages
- Use lazy loading for route components

Handle errors gracefully and test your React components.
**Error Boundaries:**
```jsx
class ErrorBoundary extends React.Component {
  state = { hasError: false };

  static getDerivedStateFromError(error) {
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    console.error('Error:', error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return <div>Something went wrong.</div>;
    }
    return this.props.children;
  }
}

function App() {
  return (
    <ErrorBoundary>
      <MyComponent />
    </ErrorBoundary>
  );
}
```

**Testing with Jest and React Testing Library:**
```jsx
import { render, screen } from '@testing-library/react';
import { fireEvent } from '@testing-library/react';
import Button from './Button';

test('renders button with text', () => {
  render(<Button>Click me</Button>);
  const button = screen.getByText('Click me');
  expect(button).toBeInTheDocument();
});

test('calls onClick when clicked', () => {
  const handleClick = jest.fn();
  render(<Button onClick={handleClick}>Click me</Button>);

  fireEvent.click(screen.getByText('Click me'));
  expect(handleClick).toHaveBeenCalledTimes(1);
});
```

**Best Practices:**
- Test user behavior, not implementation details
- Use descriptive test names
- Keep tests simple and focused
- Test edge cases and error scenarios
